    29→  auto pool_iter = active_pools_.find(key);
    30→  if (pool_iter != active_pools_.end()) {
    31→    return std::ref(*(pool_iter->second));
    32→  }
    33→  ResourceLimit& connPoolResource = host_->cluster().resourceManager(priority_).connectionPools();
